module RefModule (
    input wire clk,
    input wire enable,
    input wire reset,
    input wire d,
    output reg q
);
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            q <= 0;
        end else if (enable) begin
            q <= d;
        end
    end
endmodule
